  1	import * as React from 'react';
  2	import { Address } from '../../../types/IstioObjects';
  3	import { Table, Tbody, Td, Th, Thead, ThProps, Tr } from '@patternfly/react-table';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	import { Button, ButtonVariant } from '@patternfly/react-core';
  6	import { AddressBuilder } from './AddressBuilder';
  7	import { PFColors } from '../../../components/Pf/PfColors';
  8	import { KialiIcon } from 'config/KialiIcon';
  9	
 10	type AddressListProps = {
 11	  addressList: Address[];
 12	  onChange: (address: Address[]) => void;
 13	};
 14	
 15	const noAddressStyle = kialiStyle({
 16	  color: PFColors.Red100,
 17	  textAlign: 'center'
 18	});
 19	
 20	const addAddressStyle = kialiStyle({
 21	  marginLeft: '0.5rem',
 22	  marginTop: '0.25rem'
 23	});
 24	
 25	const columns: ThProps[] = [
 26	  {
 27	    title: '',
 28	    width: 40
 29	  },
 30	  {
 31	    title: '',
 32	    width: 60
 33	  }
 34	];
 35	
 36	export const AddressList: React.FC<AddressListProps> = (props: AddressListProps) => {
 37	  const onAddAddress = (): void => {
 38	    const newAddress: Address = {
 39	      type: 'IPAddress',
 40	      value: ''
 41	    };
 42	
 43	    const l = props.addressList;
 44	    l.push(newAddress);
 45	
 46	    props.onChange(l);
 47	  };
 48	
 49	  const onRemoveAddress = (index: number): void => {
 50	    const l = props.addressList;
 51	    l.splice(index, 1);
 52	
 53	    props.onChange(l);
 54	  };
 55	
 56	  const onChange = (address: Address, i: number): void => {
 57	    const l = props.addressList;
 58	    l[i] = address;
 59	
 60	    props.onChange(l);
 61	  };
 62	
 63	  return (
 64	    <>
 65	      <Table aria-label="Address List">
 66	        <Thead>
 67	          <Tr>
 68	            {columns.map((column, index) => (
 69	              <Th key={`column_${index}`} dataLabel={column.title} width={column.width}>
 70	                {column.title}
 71	              </Th>
 72	            ))}
 73	          </Tr>
 74	        </Thead>
 75	
 76	        <Tbody>
 77	          {props.addressList.length > 0 ? (
 78	            <>
 79	              {props.addressList.map((address, index) => (
 80	                <AddressBuilder
 81	                  key={`address_builder_${index}`}
 82	                  address={address}
 83	                  onRemoveAddress={onRemoveAddress}
 84	                  index={index}
 85	                  onChange={onChange}
 86	                ></AddressBuilder>
 87	              ))}
 88	            </>
 89	          ) : (
 90	            <Tr>
 91	              <Td colSpan={columns.length}>
 92	                <div className={noAddressStyle}>No Addresses defined</div>
 93	              </Td>
 94	            </Tr>
 95	          )}
 96	        </Tbody>
 97	      </Table>
 98	
 99	      <Button
100	        name="addAddress"
101	        variant={ButtonVariant.link}
102	        icon={<KialiIcon.AddMore />}
103	        onClick={onAddAddress}
104	        className={addAddressStyle}
105	      >
106	        Add Address to Addresses List
107	      </Button>
108	    </>
109	  );
110	};

